import{_ as t,o as a,c as r,a1 as i}from"./chunks/framework.BX4nIuL2.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"courses/fab-course/doc/6laser_cutter/basic.md","filePath":"courses/fab-course/doc/6laser_cutter/basic.md"}'),l={name:"courses/fab-course/doc/6laser_cutter/basic.md"};function s(o,e,n,c,d,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h2 id="_1-basic-knowledge-about-laser-cutter" tabindex="-1">1. Basic knowledge about laser cutter <a class="header-anchor" href="#_1-basic-knowledge-about-laser-cutter" aria-label="Permalink to &quot;1. Basic knowledge about laser cutter&quot;">​</a></h2><p><img src="https://gitlab.com/picbed/bed/uploads/544c5974ab0d136f2ea1d8b958295072/laser-cut.gif" alt=""></p><p>Laser cutting is a technology that uses a laser to cut or engraving materials, and is typically used for industrial manufacturing applications, but is also starting to be used by schools, small businesses, and hobbyists. Laser cutting works by directing the output of a high-power laser most commonly through optics. The laser optics and CNC (computer numerical control) are used to direct the material or the laser beam generated. A typical commercial laser for cutting materials involved a motion control system to follow a CNC or G-code of the pattern to be cut onto the material. The focused laser beam is directed at the material, which then either melts, burns, vaporizes away, or is blown away by a jet of gas, leaving an edge with a high-quality surface finish. Industrial laser cutters are used to cut flat-sheet material as well as structural and piping materials.</p><ul><li><p>In 1965, the first production laser cutting machine was used to drill holes in diamond dies. This machine was made by the Western Electric Engineering Research Center;</p></li><li><p>In 1967, the British pioneered laser-assisted oxygen jet cutting for metals;</p></li><li><p>In the early 1970s, this technology was put into production to cut titanium for aerospace applications. At the same time CO2 lasers were adapted to cut non-metals, such as textiles, because, at the time, CO2 lasers were not powerful enough to overcome the thermal conductivity of metals.</p><p>reference from <a href="https://en.wikipedia.org/wiki/Laser_cutting" target="_blank" rel="noreferrer">Wiki</a></p></li></ul><hr><ul><li>The basic structure of laser cutter</li></ul><p><img src="https://gitlab.com/picbed/bed/uploads/56743b8fe5e398e3c1a3562977543f97/cnc-laser-system.png" alt=""> Reference from <a href="https://am.co.za/laser/cabinet" target="_blank" rel="noreferrer">advanced machinery</a></p><ul><li>The nozzle of laser cutter <img src="https://gitlab.com/picbed/bed/uploads/9f62d3f7d32249b67301603249d1d919/LaserCutter.jpg" alt=""></li></ul><h2 id="_2-computer-controlled-cutting" tabindex="-1">2. Computer-Controlled Cutting <a class="header-anchor" href="#_2-computer-controlled-cutting" aria-label="Permalink to &quot;2. Computer-Controlled Cutting&quot;">​</a></h2><ul><li><p><a href="https://www.youtube.com/watch?v=PG9lJOnNTzQ" target="_blank" rel="noreferrer">Knife</a>:Use knife to cut the profile of material according to computer control machine. The following is some vendors <a href="https://www.rolanddga.com/products/vinyl-cutters" target="_blank" rel="noreferrer">Vinyl Cutter Machines</a> ,<a href="https://www.zund.com/en" target="_blank" rel="noreferrer">Zund</a> ,<a href="https://www.youtube.com/watch?v=PG9lJOnNTzQ" target="_blank" rel="noreferrer">Othercutter</a><img src="https://gitlab.com/picbed/bed/uploads/b632e9d47d801a0e7dc233cb9afe85e3/VINLY.png" alt=""></p></li><li><p>Laser:we can divide CO2 laser,Fiber lasers and The neodymium (Nd) and neodymium yttrium-aluminium-garnet (Nd:YAG) lasers ,introduce in the below PART3. The following is some vendors:<a href="https://www.epiloglaser.com/laser-machines/product-line.htm" target="_blank" rel="noreferrer">Epilog</a> ,<a href="https://www.ulsinc.com/technology/products" target="_blank" rel="noreferrer">Universal</a>,<a href="https://www.troteclaser.com/" target="_blank" rel="noreferrer">Trotec</a></p></li><li><p><a href="https://en.wikipedia.org/wiki/Plasma_cutting" target="_blank" rel="noreferrer">Plasma:A process that cuts through electrically conductive materials by means of an accelerated jet of hot plasma.</a>. The following is some vendors,<a href="http://forestscientific.com/cnc-plasma-cutters/" target="_blank" rel="noreferrer">Forest Scientific</a> ,<a href="https://torchmate.com/how-to-choose" target="_blank" rel="noreferrer">Torchmate</a><img src="https://gitlab.com/picbed/bed/uploads/a0a3eaaac5305b1d6e4d096a24ba3fe7/PlasmaCutteractionpix.jpg" alt=""></p></li><li><p><a href="https://en.wikipedia.org/wiki/Water_jet_cutter" target="_blank" rel="noreferrer">waterjet:An industrial tool capable of cutting a wide variety of materials using a very high-pressure jet of water, or a mixture of water and an abrasive substance</a><img src="https://gitlab.com/picbed/bed/uploads/22d4518258963a56bf19a5c66e4dbcc0/abrasive-waterjet.gif" alt=""></p></li><li><p>Hot wire,Used to cut foam. The following is some vendors:<a href="http://www.3dcutting.com/solutions/frogwire.html" target="_blank" rel="noreferrer">FROGWire</a> ,<a href="https://hotwiresystems.com/hot-wire-cnc-foam-cutters/" target="_blank" rel="noreferrer">Hotwire</a>, <a href="http://ng.cba.mit.edu/show/video/14.08.modular.mp4" target="_blank" rel="noreferrer">MTM</a></p></li><li><p><a href="https://en.wikipedia.org/wiki/Electrical_discharge_machining" target="_blank" rel="noreferrer">Electrical discharge machining (EDM), also known as spark machining, spark eroding, die sinking, wire burning or wire erosion, is a metal fabrication process whereby a desired shape is obtained by using electrical discharges (sparks)</a>. The following is some vendors:<a href="https://www.sodick.com/" target="_blank" rel="noreferrer">Sodick MTM</a>,<a href="https://www.mitsubishielectric.co.jp/fa/products/mecha/edm/premium/index.html" target="_blank" rel="noreferrer">Mitsubishielectric</a></p></li></ul><p><img src="https://gitlab.com/picbed/bed/uploads/3abfee1919052b48973291dffe78a9c2/edm1.jpg" alt=""><img src="https://gitlab.com/picbed/bed/uploads/4a943064c01aab8550101aa55d06dfa1/edm2.jpg" alt=""><img src="https://gitlab.com/picbed/bed/uploads/2547df2f87a855d0f7f661260c1344f2/Electrical_discharge_Machining.gif" alt=""></p><h2 id="_3-laser-cutter-type" tabindex="-1">3. Laser cutter type <a class="header-anchor" href="#_3-laser-cutter-type" aria-label="Permalink to &quot;3. Laser cutter type&quot;">​</a></h2><p>There are three main types of lasers used in laser cutting.</p><ul><li><p>The CO2 laser is suited for cutting, boring, and engraving. CO2 lasers are commonly &quot;pumped&quot; by passing a current through the gas mix (DC-excited) or using radio frequency energy (RF-excited). The RF method is newer and has become more popular. Since DC designs require electrodes inside the cavity, they can encounter electrode erosion and plating of electrode material on glassware and optics. Since RF resonators have external electrodes they are not prone to those problems. CO2 lasers are used for industrial cutting of many materials including titanium, stainless steel, mild steel, aluminium, plastic, wood, engineered wood, wax, fabrics, and paper.</p></li><li><p>Fiber lasers are a type of solid state laser that is rapidly growing within the metal cutting industry. Unlike CO2, Fiber technology utilizes a solid gain medium, as opposed to a gas or liquid. The “seed laser” produces the laser beam and is then amplified within a glass fiber. With a wavelength of only 1.064 micrometers fiber lasers produce an extremely small spot size (up to 100 times smaller compared to the CO2),making it ideal for cutting reflective metal material. This is one of the main advantages of Fiber compared to CO2.</p></li><li><p>The neodymium (Nd) and neodymium yttrium-aluminium-garnet (Nd:YAG) lasers are identical in style and differ only in application.</p><ul><li>Nd is used for boring and where high energy but low repetition are required.</li><li>The Nd:YAG laser is used where very high power is needed and for boring and engraving.</li></ul></li></ul><h4 id="_4-material" tabindex="-1">4.Material <a class="header-anchor" href="#_4-material" aria-label="Permalink to &quot;4.Material&quot;">​</a></h4><ul><li>Acrylic</li><li>Glass</li><li>Metal</li><li>Textiles</li><li>Wood</li></ul><h2 id="_5-the-laser-cutter-in-our-lab" tabindex="-1">5.The laser cutter in our lab <a class="header-anchor" href="#_5-the-laser-cutter-in-our-lab" aria-label="Permalink to &quot;5.The laser cutter in our lab&quot;">​</a></h2><p><img src="https://gitlab.com/picbed/bed/uploads/1940a8cbe0f567c4b2e3adc15fee716a/WechatIMG80.jpeg" alt=""></p><table tabindex="0"><thead><tr><th>Product</th><th style="text-align:right;">HX960</th></tr></thead><tbody><tr><td>Working area</td><td style="text-align:right;">900*600mm</td></tr><tr><td>Machine size</td><td style="text-align:right;">1500<em>1200</em>1100mm</td></tr><tr><td>Engraving speed</td><td style="text-align:right;">0-600mm/s</td></tr><tr><td>Laser power</td><td style="text-align:right;">80W</td></tr><tr><td>Resolution ratio</td><td style="text-align:right;">0.025mm</td></tr><tr><td>The min word</td><td style="text-align:right;">Chinese Character2mm /letter1mm</td></tr><tr><td>Power</td><td style="text-align:right;">AC220V±10%,50HZ,&lt;2500W</td></tr><tr><td>Formate</td><td style="text-align:right;">AI, BMP、JPEG、PCX、TGA、CDR、DWG、TIFF、PLT、DXF</td></tr></tbody></table><h2 id="_6-reference" tabindex="-1">6. Reference <a class="header-anchor" href="#_6-reference" aria-label="Permalink to &quot;6. Reference&quot;">​</a></h2><ul><li><a href="http://fab.academany.org/2018/lectures/fab-20180207.html" target="_blank" rel="noreferrer">Recording from fablab 2018</a></li><li><a href="http://academy.cba.mit.edu/classes/computer_cutting/index.html" target="_blank" rel="noreferrer">Basic infromation about laser cutter</a></li></ul>',21)])])}const p=t(l,[["render",s]]);export{m as __pageData,p as default};
